      <span style="font-size:1.4rem;">🦋</span>
      <div class="feed-tabs d-flex gap-4 ms-3">
        <button class="tab-btn" [class.active]="activeTab === 'discover'" (click)="setTab('discover')">Discover</button>
        <button class="tab-btn" [class.active]="activeTab === 'following'" (click)="setTab('following')">Following</button>
        <button class="tab-btn" [class.active]="activeTab === 'video'" (click)="setTab('video')">Video</button>
      </div>
    </div>

    <div class="post-composer d-flex align-items-start gap-3 p-3 border-bottom">
      <div class="avatar-sm bg-primary d-flex align-items-center justify-content-center flex-shrink-0 rounded-circle" style="width:40px;height:40px;">
        <span class="text-white fw-bold small">@</span>
      </div>
      <button class="form-control text-start text-muted border-0 bg-transparent shadow-none ps-0" (click)="openNewPost()">
        What's up?
      </button>
      <button class="btn btn-sm btn-outline-secondary rounded" (click)="openNewPost()">🖼️</button>
    </div>

    <div class="posts-feed">
      <div class="post-item border-bottom p-3" *ngFor="let post of posts">
        <div class="d-flex gap-3">
          <img [src]="post.author.avatar || 'https://i.pravatar.cc/40?u=' + post.author.handle"
            class="rounded-circle flex-shrink-0" width="44" height="44" [alt]="post.author.displayName">
          <div class="flex-grow-1 min-w-0">
            <div class="d-flex align-items-center gap-1 flex-wrap mb-1">
              <span class="fw-bold text-dark small">{{ post.author.displayName }}</span>
              <span *ngIf="post.author.verified" class="text-primary small">✓</span>
              <span class="text-muted small">@{{ post.author.handle }}</span>
              <span class="text-muted small">· {{ post.createdAt }}</span>
            </div>
            <p class="mb-2" style="font-size:0.95rem;line-height:1.5;">{{ post.text }}</p>
            <p class="mb-2" *ngIf="post.hashtags?.length">
              <span class="text-primary fw-medium small me-1" *ngFor="let tag of post.hashtags">{{ tag }}</span>
            </p>
            <img *ngIf="post.image" [src]="post.image" class="rounded-3 mb-2 w-100" style="max-height:400px;object-fit:cover;" [alt]="post.text">
            <div class="d-flex gap-4 mt-2">
              <button class="action-btn" (click)="toggleRepost(post)" [class.active-repost]="post.reposted">
                🔁 {{ formatCount(post.reposts) }}
              </button>
              <button class="action-btn">💬 {{ formatCount(post.replies) }}</button>
              <button class="action-btn" (click)="toggleLike(post)" [class.liked]="post.liked">
                {{ post.liked ? '❤️' : '🤍' }} {{ formatCount(post.likes) }}
              </button>
              <button class="action-btn ms-auto">🔖</button>
              <button class="action-btn">📤</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  </main>

  <app-right-sidebar></app-right-sidebar>
</div>

<!-- New Post Modal -->
<div class="modal-overlay" *ngIf="showNewPostModal" (click)="closeNewPost()">
  <div class="new-post-modal card shadow-lg border-0 rounded-4 p-4" (click)="$event.stopPropagation()">
    <div class="d-flex justify-content-between align-items-center mb-3">
      <button class="btn btn-link text-decoration-none text-primary p-0 fw-medium" (click)="closeNewPost()">Cancel</button>
      <div class="d-flex gap-3">
        <button class="btn btn-sm btn-link text-decoration-none text-muted p-0">Drafts</button>
        <button class="btn btn-primary rounded-pill px-4 fw-semibold" (click)="submitPost()" [disabled]="!newPostText.trim() || postLoading">Post</button>
      </div>
    </div>
    <div class="d-flex gap-3">
      <div class="rounded-circle bg-primary d-flex align-items-center justify-content-center flex-shrink-0" style="width:40px;height:40px;">
        <span class="text-white fw-bold small">@</span>
      </div>
      <textarea class="form-control border-0 shadow-none flex-grow-1" placeholder="What's up?" style="resize:none;"
        rows="5" [value]="newPostText" (input)="newPostText = $any($event.target).value" maxlength="300"></textarea>
    </div>
    <hr>
    <div class="d-flex align-items-center justify-content-between">
      <div class="d-flex gap-3">
        <button class="btn btn-sm btn-link text-muted">🖼️</button>
        <button class="btn btn-sm btn-link text-muted">GIF</button>
        <button class="btn btn-sm btn-link text-muted">😊</button>
      </div>
      <span class="text-muted small">{{ 300 - newPostText.length }}</span>
    </div>
  </div>
</div>
